  describe('register()', () => {
    it('declares concept name', async () => {
      if (typeof credentialHandler.register !== 'function') return;
      const storage = createInMemoryStorage();
      const program = credentialHandler.register({});
      // If it's a StorageProgram, interpret it
      const result = (program?.instructions && !program.variant)
        ? await interpret(program, storage)
        : program;
      if (!result?.variant) return; // handler does not support register introspection
      expect(result.variant).toBe('ok');
      const name = result.output?.name ?? result.name;
      expect(name).toBe('Credential');
    });
  });

  describe('invariant examples', () => {
    it("create then store then load", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(credentialHandler.create({ profile: "test-c", name: "prod", endpoint: "wss://prod.example.com", method: "apikey" }), storage);
      expect(createResult0.variant).toBe("ok");
      let profile = createResult0.output["profile"];
      let c = profile;
      const storeResult1 = await interpret(credentialHandler.store({ profile: c, token: "tok_prod_123", expiresAt: false }), storage);
      expect(storeResult1.variant).toBe("ok");
      profile = storeResult1.output["profile"];
      const thenResult0 = await interpret(credentialHandler.load({ profile: c }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

    it("create without store returns expired on load", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(credentialHandler.create({ profile: "test-c", name: "bare", endpoint: "wss://bare.example.com", method: "token" }), storage);
      expect(createResult0.variant).toBe("ok");
      let profile = createResult0.output["profile"];
      let c = profile;
      const thenResult0 = await interpret(credentialHandler.load({ profile: c }), storage);
      expect(thenResult0.variant).toBe("expired");
    });

    it("duplicate name rejected", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(credentialHandler.create({ profile: "test-c1", name: "dev", endpoint: "wss://dev.example.com", method: "apikey" }), storage);
      expect(createResult0.variant).toBe("ok");
      let profile = createResult0.output["profile"];
      let c1 = profile;
      const thenResult0 = await interpret(credentialHandler.create({ profile: "test-c2", name: "dev", endpoint: "wss://other.example.com", method: "oauth" }), storage);
      expect(thenResult0.variant).toBe("duplicate");
    });

    it("remove then load returns notfound", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(credentialHandler.create({ profile: "test-c", name: "tmp", endpoint: "wss://tmp.example.com", method: "token" }), storage);
      expect(createResult0.variant).toBe("ok");
      let profile = createResult0.output["profile"];
      let c = profile;
      const removeResult1 = await interpret(credentialHandler.remove({ profile: c }), storage);
      expect(removeResult1.variant).toBe("ok");
      profile = removeResult1.output["profile"];
      const thenResult0 = await interpret(credentialHandler.load({ profile: c }), storage);
      expect(thenResult0.variant).toBe("notfound");
    });

    it("list never exposes tokens", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(credentialHandler.create({ profile: "test-c", name: "safe", endpoint: "wss://safe.example.com", method: "apikey" }), storage);
      expect(createResult0.variant).toBe("ok");
      let profile = createResult0.output["profile"];
      let c = profile;
      const storeResult1 = await interpret(credentialHandler.store({ profile: c, token: "secret_token_value", expiresAt: false }), storage);
      expect(storeResult1.variant).toBe("ok");
      profile = storeResult1.output["profile"];
      const thenResult0 = await interpret(credentialHandler.list({  }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: profiles have identity fields', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ profile: fc.string(), name: fc.string({ minLength: 1, maxLength: 50 }), endpoint: fc.string({ minLength: 1, maxLength: 50 }), method: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('store'), input: fc.record({ profile: fc.string(), token: fc.string({ minLength: 1, maxLength: 50 }), expiresAt: fc.string() }) }),
              fc.record({ action: fc.constant('load'), input: fc.record({ profile: fc.string() }) }),
              fc.record({ action: fc.constant('refresh'), input: fc.record({ profile: fc.string() }) }),
              fc.record({ action: fc.constant('remove'), input: fc.record({ profile: fc.string() }) }),
              fc.record({ action: fc.constant('list'), input: fc.record({  }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = credentialHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(credentialHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: unset profile has token', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ profile: fc.string(), name: fc.string({ minLength: 1, maxLength: 50 }), endpoint: fc.string({ minLength: 1, maxLength: 50 }), method: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('store'), input: fc.record({ profile: fc.string(), token: fc.string({ minLength: 1, maxLength: 50 }), expiresAt: fc.string() }) }),
              fc.record({ action: fc.constant('load'), input: fc.record({ profile: fc.string() }) }),
              fc.record({ action: fc.constant('refresh'), input: fc.record({ profile: fc.string() }) }),
              fc.record({ action: fc.constant('remove'), input: fc.record({ profile: fc.string() }) }),
              fc.record({ action: fc.constant('list'), input: fc.record({  }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = credentialHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(credentialHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: unset profile has token
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

